import{_ as e,c as t,o as _,V as s}from"./chunks/framework.1sOznGPE.js";const V=JSON.parse('{"title":"Vue.set方法原理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/interview/vue/vue/Vue.set方法原理.md","filePath":"guide/interview/vue/vue/Vue.set方法原理.md","lastUpdated":1719242077000}'),a={name:"guide/interview/vue/vue/Vue.set方法原理.md"},o=s('<h1 id="vue-set方法原理" tabindex="-1">Vue.set方法原理 <a class="header-anchor" href="#vue-set方法原理" aria-label="Permalink to &quot;Vue.set方法原理&quot;">​</a></h1><p>了解 Vue 响应式原理的同学都知道在两种情况下修改数据 Vue 是不会触发视图更新的</p><p>1.在实例创建之后添加新的属性到实例上（给响应式对象新增属性）</p><p>2.直接更改数组下标来修改数组的值</p><p>Vue.set 或者说是$set 原理如下</p><p>因为响应式数据 我们给对象和数组本身都增加了<code>__ob__</code>属性，代表的是 Observer 实例。当给对象新增不存在的属性 首先会把新的属性进行响应式跟踪 然后会触发对象<code>__ob__</code>的 dep 收集到的 watcher 去更新，当修改数组索引时我们调用数组本身的 splice 方法去更新数组</p>',6),r=[o];function u(c,i,d,n,p,l){return _(),t("div",null,r)}const h=e(a,[["render",u]]);export{V as __pageData,h as default};
